-- schema-v6 실행 중 CHECK 오류로 누락된 7개 카테고리 재삽입
-- (surfing, skiing, scuba, nature, animals, festivals, countries)

-- 기존 중복 방지: 이미 있는 카테고리는 삭제 후 재삽입
DELETE FROM public.challenge_certifications WHERE challenge_id IN (
  SELECT id FROM public.challenges WHERE category IN ('surfing','skiing','scuba','nature','animals','festivals','countries')
);
DELETE FROM public.challenges WHERE category IN ('surfing','skiing','scuba','nature','animals','festivals','countries');

